assertions.check:
from pyspark.sql.functions import upper, trim
valid = {'NORTH','SOUTH','EAST','WEST'}
actual = {r[0] for r in df_bronze.select(upper(trim(col('rgn_code')))).distinct().collect()}
assert actual.issubset(valid), f'Invalid regions found: {actual - valid}'

valid_tiers = {'low','medium','high','critical'}
actual_tiers = {r[0] for r in df_silver.select('tier').distinct().collect()}
assert actual_tiers.issubset(valid_tiers)
low_count = df_silver.filter((col('daily_kw') < 500) & (col('tier') != 'low')).count()
assert low_count == 0, 'Some rows with daily_kw < 500 are not tier low'

gold_map = {r['region']: r['reading_count'] for r in df_gold.collect()}
from pyspark.sql.functions import count as cnt
silver_map = {r['region']: r['n'] for r in df_silver.groupBy('region').agg(cnt('*').alias('n')).collect()}
assert gold_map == silver_map, f'reading_count mismatch: gold={gold_map}, silver={silver_map}'

assert df_validation.count() == 4
regions = {r['region'] for r in df_validation.collect()}
assert regions == {'NORTH','SOUTH','EAST','WEST'}, f'Expected NORTH/SOUTH/EAST/WEST, got {regions}'
